HEADER = '''#!/usr/bin/env python3
"""Build Industry Expansion Pack V2 Chinese vocabulary seed files."""
from __future__ import annotations

import re
import sys
from pathlib import Path

SCRIPT_DIR = Path(__file__).resolve().parent
OUTPUT_DIR = SCRIPT_DIR / "vocab_data"

DOMAINS = [
    "bakery", "coffee", "food_order", "medical", "meeting", "milk_tea",
    "tech_ai", "tourism_hotel", "tourism_pickup", "tourism_route",
    "tourism_transport", "transport",
]

TARGET_MIN = 950
TARGET_MAX = 1200

CJK_RE = re.compile(r"[\\u4e00-\\u9fff]")
FORBIDDEN_COMPOUNDS = re.compile(r"确认|预订|打包|菜单|堂食|点餐|外卖|发票|排号")
PHRASE_SUFFIX = re.compile(r"(服务|确认)$")
GENERIC_BLOCK = frozenset({"服务", "工作", "发布", "模型", "优化", "下文"})


def _block(text: str) -> list[str]:
    return [w.strip() for w in text.split() if w.strip()]


def _compound(prefixes: list[str], suffixes: list[str]) -> list[str]:
    out: list[str] = []
    for p in prefixes:
        for s in suffixes:
            t = p + s
            if 2 <= len(t) <= 5:
                out.append(t)
    return out


def cjk_count(word: str) -> int:
    return len(CJK_RE.findall(word))


def validate_term(word: str) -> bool:
    w = word.strip()
    if not w or w in GENERIC_BLOCK:
        return False
    if w.endswith("的") or w.endswith("了"):
        return False
    if "请" in w or "吗" in w:
        return False
    if FORBIDDEN_COMPOUNDS.search(w):
        return False
    if len(w) >= 3 and PHRASE_SUFFIX.search(w):
        return False
    n = cjk_count(w)
    return n == len(w) and 2 <= n <= 5


def _filter_terms(terms: list[str]) -> list[str]:
    seen: set[str] = set()
    out: list[str] = []
    for t in terms:
        if not validate_term(t) or t in seen:
            continue
        seen.add(t)
        out.append(t)
    return out

'''

FOOTER = '''

def _collect(domain: str) -> list[str]:
    raw: list[str] = []
    for _sub, batch in DOMAIN_BUILDERS[domain]().items():
        raw.extend(batch)
    return _filter_terms(raw)


def write_domain(domain: str, terms: list[str]) -> int:
    OUTPUT_DIR.mkdir(parents=True, exist_ok=True)
    path = OUTPUT_DIR / f"{domain}.txt"
    path.write_text("\\n".join(terms) + "\\n", encoding="utf-8")
    return len(terms)


def main() -> int:
    print("=== Industry Pack V2 Vocab Data ===")
    total = 0
    errors: list[str] = []
    for domain in DOMAINS:
        terms = _collect(domain)
        n = len(terms)
        if n < TARGET_MIN:
            errors.append(f"{domain}: {n} terms (need {TARGET_MIN}+)")
        if n > TARGET_MAX:
            terms = terms[:TARGET_MAX]
            n = len(terms)
        count = write_domain(domain, terms)
        print(f"  {domain}: {count}")
        total += count
    print(f"  TOTAL: {total}")
    if errors:
        print("\\nERRORS:")
        for e in errors:
            print(f"  - {e}")
        return 1
    return 0


if __name__ == "__main__":
    sys.exit(main())
'''

